questions.solution:
data class Request(
    val url: String,
    val method: String,
    val headers: Map<String, String>
)

class RequestBuilder {
    private var url = ""
    private var method = "GET"
    private val headers = mutableMapOf<String, String>()

    fun url(value: String) { url = value }
    fun method(value: String) { method = value }
    fun header(key: String, value: String) { headers[key] = value }

    fun build() = Request(url, method, headers)
}

fun request(init: RequestBuilder.() -> Unit): Request {
    return RequestBuilder().apply(init).build()
}

