questions.solution:
open class Animal
class Dog : Animal()
class Cat : Animal()

fun addAnimals(animals: MutableList<in Animal>) {
    animals.add(Dog())
    animals.add(Cat())
}

// But wait — this now allows adding Dogs AND Cats to a MutableList<Dog>!
// The real fix is to change the design:
fun addAnimals(animals: MutableList<Animal>) {
    animals.add(Dog())
    animals.add(Cat())
}

fun main() {
    val animals: MutableList<Animal> = mutableListOf()
    addAnimals(animals)  // ✅ Works
}

